// When a developer touches this code,
// the system surfaces relevant context:
//
// > This service uses eventual consistency.
// > See ADR-042 for why we chose this pattern.
// > Last modified by: @sarah (ask her about
// >   the retry logic edge cases)

async function processOrder(order: Order) {
  await eventBus.publish('OrderPlaced', order);
  // Don't await — this is eventually consistent
}
